export function KenyaCountyMap() {
  const [selectedCounty, setSelectedCounty] = useState<CountyMeta | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const filteredCounties = useMemo(() => {
    const term = searchTerm.trim().toLowerCase();

    if (!term) {
      return KENYA_COUNTIES;
    }

    return KENYA_COUNTIES.filter((county) =>
      [county.name, county.region, county.code]
        .some((value) => String(value).toLowerCase().includes(term))
    );
  }, [searchTerm]);

  const mapMarkup = useMemo(() => {
    if (!selectedCounty) {
      return SVG_MARKUP;
    }

    return SVG_MARKUP.replace(
      `class="county" id="c${selectedCounty.code}"`,
      `class="county active" id="c${selectedCounty.code}"`
    );
  }, [selectedCounty]);

  const selectCounty = (countyName: string | null) => {
    if (!countyName) {
      return;
    }

    const county = KENYA_COUNTIES.find((item) => item.name === countyName);

    if (county) {
      setSelectedCounty(county);
    }
  };

  const handleMapClick = (event: React.MouseEvent<HTMLDivElement>) => {
    const target = event.target as Element;
    const countyPath = target.closest('.county');
    selectCounty(countyPath?.getAttribute('data-name') || null);
  };

  return (
    <div className="grid grid-cols-1 xl:grid-cols-[minmax(0,1fr)_320px] gap-6 items-stretch">
      <div className="relative min-h-[620px] rounded-lg border border-neutral-200 bg-[#0a0e1a] overflow-hidden">
        <div className="absolute left-4 top-4 z-10 inline-flex items-center gap-2 rounded-md border border-white/10 bg-white/95 px-3 py-1.5 text-sm font-medium text-neutral-700 shadow-sm">
          <MapPin className="h-4 w-4 text-brand-600" />
          Kenya county reference map
        </div>
        <div
          className="h-[620px] px-4 pt-12 pb-4 sm:px-8 sm:pt-14"
          onClick={handleMapClick}
          dangerouslySetInnerHTML={{ __html: mapMarkup }} />
      </div>

      <aside className="rounded-lg border border-neutral-200 bg-white shadow-sm overflow-hidden flex flex-col min-h-[620px]">
        <div className="border-b border-neutral-200 bg-neutral-50 px-5 py-4">
          <h2 className="text-sm font-semibold uppercase tracking-wide text-neutral-500">
            County Details
          </h2>
          {selectedCounty ? (
            <div className="mt-3">
              <div className="text-2xl font-bold text-neutral-900">
                {selectedCounty.name}
              </div>
              <div className="mt-2 flex items-center gap-2 text-sm text-neutral-600">
                <span
                  className="h-3 w-3 rounded-sm"
                  style={{ backgroundColor: selectedCounty.color }} />
                {selectedCounty.region} Region
              </div>
              <div className="mt-3 inline-flex rounded border border-neutral-200 bg-white px-2 py-1 text-xs font-semibold text-neutral-500">
                County No. {String(selectedCounty.code).padStart(2, '0')}
              </div>
            </div>
          ) : (
            <p className="mt-3 text-sm text-neutral-500">
              Select a county on the map or from the list.
            </p>
          )}
        </div>

        <div className="grid grid-cols-2 border-b border-neutral-200">
          <div className="px-5 py-4">
            <div className="text-xs uppercase tracking-wide text-neutral-400">Devices</div>
            <div className="mt-1 text-2xl font-bold text-neutral-900">0</div>
          </div>
          <div className="border-l border-neutral-200 px-5 py-4">
            <div className="text-xs uppercase tracking-wide text-neutral-400">Facilities</div>
            <div className="mt-1 text-2xl font-bold text-neutral-900">0</div>
          </div>
        </div>

        <div className="border-b border-neutral-200 px-5 py-4">
          <div className="relative">
            <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-neutral-400" />
            <input
              value={searchTerm}
              onChange={(event) => setSearchTerm(event.target.value)}
              placeholder="Search county..."
              className="w-full rounded-md border border-neutral-300 py-2 pl-9 pr-3 text-sm focus:border-brand-500 focus:ring-brand-500" />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto py-2">
          {filteredCounties.map((county) => (
            <button
              key={county.code}
              type="button"
              onClick={() => setSelectedCounty(county)}
              className={`flex w-full items-center gap-3 px-5 py-2 text-left text-sm transition-colors ${selectedCounty?.code === county.code ? 'bg-brand-50 text-brand-800' : 'text-neutral-600 hover:bg-neutral-50 hover:text-neutral-900'}`}>
              <span
                className="h-2.5 w-2.5 rounded-full"
                style={{ backgroundColor: county.color }} />
              <span className="flex-1 truncate">{county.name}</span>
              <span className="text-xs tabular-nums text-neutral-400">
                {String(county.code).padStart(2, '0')}
              </span>
            </button>
          ))}
        </div>
      </aside>
    </div>
  );
}
